def can_unlock(password, words):
    # Check if any word is the password directly
    if password in words:
        return True
    # Check if any pair of words can form the password
    first_chars = set()
    second_chars = set()
    for word in words:
        first_chars.add(word[0])
        second_chars.add(word[1])
    # Check if there's a word ending with password[0] and another starting with password[1]
    for word in words:
        if word[1] == password[0]:
            for other_word in words:
                if other_word[0] == password[1]:
                    return True
    return False

password = input().strip()
n = int(input())
words = [input().strip() for _ in range(n)]

if can_unlock(password, words):
    print("YES")
else:
    print("NO")
